create extension if not exists pgcrypto;
alter table public.sales_leads add column if not exists next_follow_up_at timestamptz, add column if not exists revenue_stage text not null default 'New Lead', add column if not exists assigned_owner_key text, add column if not exists next_action text, add column if not exists next_action_due_at timestamptz, add column if not exists estimated_value_cents integer not null default 0, add column if not exists engagement_score integer not null default 0, add column if not exists response_likelihood_score integer not null default 0, add column if not exists urgency_score integer not null default 0, add column if not exists conversion_probability_score integer not null default 0, add column if not exists revenue_priority_score integer not null default 0, add column if not exists latest_outreach_channel text, add column if not exists latest_outreach_at timestamptz, add column if not exists next_recommended_channel text, add column if not exists revenue_pipeline_updated_at timestamptz not null default now(), add column if not exists revenue_metadata jsonb not null default '{}'::jsonb;
do $$ begin if not exists (select 1 from pg_constraint where conname='sales_leads_revenue_stage_check' and conrelid='public.sales_leads'::regclass) then alter table public.sales_leads add constraint sales_leads_revenue_stage_check check (revenue_stage in ('New Lead','AI Queued','Outreach Scheduled','Email Sent','Awaiting Response','Follow-Up #1','Follow-Up #2','Follow-Up #3','Replied','Interested','Intake Started','Intake Completed','Proposal Sent','Negotiation','Closed Won','Closed Lost','Future Opportunity','Do Not Contact')); end if; end $$;
do $$ begin if not exists (select 1 from pg_constraint where conname='sales_leads_revenue_owner_check' and conrelid='public.sales_leads'::regclass) then alter table public.sales_leads add constraint sales_leads_revenue_owner_check check (assigned_owner_key is null or assigned_owner_key in ('jason','heather','josh','chelsi','unassigned')); end if; end $$;
create index if not exists sales_leads_revenue_stage_idx on public.sales_leads (revenue_stage, revenue_priority_score desc, updated_at desc);
create index if not exists sales_leads_next_action_due_idx on public.sales_leads (next_action_due_at) where next_action_due_at is not null;
create index if not exists sales_leads_assigned_owner_revenue_idx on public.sales_leads (assigned_owner_key, revenue_stage);
create index if not exists sales_leads_revenue_metadata_gin_idx on public.sales_leads using gin (revenue_metadata);
update public.sales_leads set revenue_stage=case when do_not_contact is true or sms_opt_out is true then 'Do Not Contact' when status='dead' then 'Closed Lost' when status='closed' then 'Closed Won' when status='payment_sent' then 'Proposal Sent' when status='interested' then 'Interested' when status='replied' then 'Replied' when status='contacted' then 'Awaiting Response' when status='queued' then 'New Lead' else coalesce(revenue_stage,'New Lead') end, assigned_owner_key=coalesce(assigned_owner_key,'unassigned'), latest_outreach_at=coalesce(latest_outreach_at,last_contacted_at), next_action_due_at=coalesce(next_action_due_at,next_follow_up_at), estimated_value_cents=greatest(coalesce(estimated_value_cents,0),greatest(30000,coalesce(score,0)*900)), engagement_score=least(100,greatest(0,coalesce(score,0)+case when buying_signal then 18 else 0 end+least(coalesce(total_replies,0)*12,36)+least(coalesce(total_messages_sent,0)*2,10))), response_likelihood_score=least(100,greatest(0,coalesce(score,0)+case when status in ('replied','interested','payment_sent','closed') then 25 else 0 end+least(coalesce(total_replies,0)*15,40))), urgency_score=least(100,greatest(0,case when next_follow_up_at is not null and next_follow_up_at<=now() then 40 else 0 end+case when status='replied' then 30 else 0 end+case when status='payment_sent' then 25 else 0 end+case when last_reply_at is not null and last_reply_at<=now()-interval '12 hours' then 20 else 0 end)), conversion_probability_score=least(100,greatest(0,coalesce(score,0)+case when buying_signal then 20 else 0 end+case when status in ('interested','payment_sent','closed') then 25 else 0 end)), revenue_priority_score=least(100,greatest(0,coalesce(score,0)+case when buying_signal then 15 else 0 end+case when status in ('replied','interested','payment_sent') then 25 else 0 end+case when next_follow_up_at is not null and next_follow_up_at<=now() then 15 else 0 end)), next_action=coalesce(next_action,case when do_not_contact is true or sms_opt_out is true then 'Do not contact. Keep suppression visible.' when status='payment_sent' then 'Review checkout state and approve a payment-safe recovery follow-up.' when status='interested' then 'Move lead toward intake, proposal, booking, or quote path.' when status='replied' then 'Reply from inbox or approve the AI-assisted response.' when status='contacted' then 'Watch response window and prepare follow-up.' else 'Qualify lead, assign owner, and choose the first approved outreach step.' end), next_recommended_channel=coalesce(next_recommended_channel,case when email is not null then 'email' when phone is not null then 'call' when facebook_url is not null then 'facebook_dm' else 'manual' end), revenue_pipeline_updated_at=now() where true;
create table if not exists public.revenue_pipeline_items (id uuid primary key default gen_random_uuid(), source_system text not null, source_id text not null, business_line text not null default 'unknown' check (business_line in ('targeted_mailing','inventory_procurement','political','government_contracting','unknown')), primary_stage text not null default 'New Lead' check (primary_stage in ('New Lead','AI Queued','Outreach Scheduled','Email Sent','Awaiting Response','Follow-Up #1','Follow-Up #2','Follow-Up #3','Replied','Interested','Intake Started','Intake Completed','Proposal Sent','Negotiation','Closed Won','Closed Lost','Future Opportunity','Do Not Contact')), lead_name text, organization_name text, contact_email text, contact_phone text, city text, county text, state text, category text, campaign_type text, assigned_owner_key text check (assigned_owner_key is null or assigned_owner_key in ('jason','heather','josh','chelsi','unassigned')), estimated_value_cents integer not null default 0, engagement_score integer not null default 0 check (engagement_score between 0 and 100), response_likelihood_score integer not null default 0 check (response_likelihood_score between 0 and 100), urgency_score integer not null default 0 check (urgency_score between 0 and 100), conversion_probability_score integer not null default 0 check (conversion_probability_score between 0 and 100), revenue_priority_score integer not null default 0 check (revenue_priority_score between 0 and 100), latest_outreach_channel text, latest_outreach_at timestamptz, latest_reply_at timestamptz, next_action text, next_action_due_at timestamptz, next_recommended_channel text, status text not null default 'active' check (status in ('active','paused','completed','lost','suppressed','archived')), source_url text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now(), unique (source_system, source_id));
create index if not exists revenue_pipeline_items_stage_idx on public.revenue_pipeline_items (primary_stage, revenue_priority_score desc, updated_at desc);
create index if not exists revenue_pipeline_items_due_idx on public.revenue_pipeline_items (next_action_due_at) where next_action_due_at is not null;
create index if not exists revenue_pipeline_items_owner_idx on public.revenue_pipeline_items (assigned_owner_key, primary_stage);
create index if not exists revenue_pipeline_items_business_line_idx on public.revenue_pipeline_items (business_line, campaign_type, primary_stage);
create index if not exists revenue_pipeline_items_contact_idx on public.revenue_pipeline_items (lower(contact_email)) where contact_email is not null;
create table if not exists public.revenue_pipeline_tasks (id uuid primary key default gen_random_uuid(), pipeline_item_id uuid references public.revenue_pipeline_items(id) on delete cascade, source_system text, source_id text, task_type text not null default 'next_action' check (task_type in ('assign_owner','manual_review','approve_message','send_email','send_follow_up','reply','recover_intake','send_proposal','book_meeting','call','no_action','next_action')), channel text not null default 'manual' check (channel in ('email','sms','facebook_dm','instagram_dm','linkedin','facebook_group','call','manual')), title text not null, detail text, assigned_owner_key text check (assigned_owner_key is null or assigned_owner_key in ('jason','heather','josh','chelsi','unassigned')), due_at timestamptz, priority text not null default 'medium' check (priority in ('low','medium','high','urgent')), status text not null default 'open' check (status in ('open','in_progress','completed','snoozed','cancelled')), approval_required boolean not null default true, approval_queue_id uuid references public.revenue_message_approval_queue(id) on delete set null, completed_at timestamptz, completed_by uuid references public.profiles(id) on delete set null, snoozed_until timestamptz, dedupe_key text, metadata jsonb not null default '{}'::jsonb, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create unique index if not exists revenue_pipeline_tasks_dedupe_uidx on public.revenue_pipeline_tasks (dedupe_key) where dedupe_key is not null;
create index if not exists revenue_pipeline_tasks_status_due_idx on public.revenue_pipeline_tasks (status, due_at, priority);
create index if not exists revenue_pipeline_tasks_owner_idx on public.revenue_pipeline_tasks (assigned_owner_key, status, due_at);
create index if not exists revenue_pipeline_tasks_item_idx on public.revenue_pipeline_tasks (pipeline_item_id, created_at desc);
create table if not exists public.revenue_strategy_insights (id uuid primary key default gen_random_uuid(), insight_date date not null default current_date, insight_type text not null check (insight_type in ('focus','pause','scale','message','sender','timing','channel','risk','conversion')), title text not null, detail text not null, recommendation text not null, evidence jsonb not null default '{}'::jsonb, confidence numeric(5,4) not null default 0, impact text not null default 'medium', status text not null default 'active' check (status in ('active','accepted','dismissed','expired')), expires_at timestamptz, created_at timestamptz not null default now(), updated_at timestamptz not null default now());
create index if not exists revenue_strategy_insights_date_idx on public.revenue_strategy_insights (insight_date desc, insight_type, status);
insert into public.revenue_pipeline_items (source_system,source_id,business_line,primary_stage,lead_name,organization_name,contact_email,contact_phone,city,state,category,assigned_owner_key,estimated_value_cents,engagement_score,response_likelihood_score,urgency_score,conversion_probability_score,revenue_priority_score,latest_outreach_channel,latest_outreach_at,latest_reply_at,next_action,next_action_due_at,next_recommended_channel,status,metadata,created_at,updated_at) select 'sales_leads',id::text,case when category ilike '%political%' then 'political' when category ilike '%procurement%' or category ilike '%supply%' or category ilike '%restaurant%' or category ilike '%bakery%' then 'inventory_procurement' else 'targeted_mailing' end,revenue_stage,contact_name,business_name,email,phone,city,state,category,assigned_owner_key,estimated_value_cents,engagement_score,response_likelihood_score,urgency_score,conversion_probability_score,revenue_priority_score,latest_outreach_channel,latest_outreach_at,last_reply_at,next_action,next_action_due_at,next_recommended_channel,case when revenue_stage='Do Not Contact' then 'suppressed' when revenue_stage in ('Closed Won','Closed Lost') then 'completed' else 'active' end,jsonb_build_object('source',source,'priority',priority,'score',score,'buying_signal',buying_signal,'do_not_contact',do_not_contact,'sms_opt_out',sms_opt_out)||coalesce(revenue_metadata,'{}'::jsonb),created_at,updated_at from public.sales_leads on conflict (source_system, source_id) do update set business_line=excluded.business_line, primary_stage=excluded.primary_stage, lead_name=excluded.lead_name, organization_name=excluded.organization_name, contact_email=excluded.contact_email, contact_phone=excluded.contact_phone, city=excluded.city, state=excluded.state, category=excluded.category, assigned_owner_key=excluded.assigned_owner_key, estimated_value_cents=excluded.estimated_value_cents, engagement_score=excluded.engagement_score, response_likelihood_score=excluded.response_likelihood_score, urgency_score=excluded.urgency_score, conversion_probability_score=excluded.conversion_probability_score, revenue_priority_score=excluded.revenue_priority_score, latest_outreach_at=excluded.latest_outreach_at, latest_reply_at=excluded.latest_reply_at, next_action=excluded.next_action, next_action_due_at=excluded.next_action_due_at, next_recommended_channel=excluded.next_recommended_channel, status=excluded.status, metadata=public.revenue_pipeline_items.metadata||excluded.metadata, updated_at=now();
insert into public.revenue_pipeline_items (source_system,source_id,business_line,primary_stage,lead_name,organization_name,contact_email,contact_phone,city,county,state,category,campaign_type,assigned_owner_key,estimated_value_cents,engagement_score,response_likelihood_score,urgency_score,conversion_probability_score,revenue_priority_score,latest_outreach_at,next_action,next_action_due_at,next_recommended_channel,status,source_url,metadata,created_at,updated_at) select 'outreach_prospects',id::text,case when campaign_type='political' or category='Political Outreach' then 'political' when campaign_type='supplyfy' or category='Procurement / Supplify' then 'inventory_procurement' when campaign_type='government_contracting' or category='Government Contracting' then 'government_contracting' else 'targeted_mailing' end,case when status='do_not_contact' or opted_out_at is not null then 'Do Not Contact' when status='queued' then 'Outreach Scheduled' when status='contacted' then 'Awaiting Response' when status='follow_up' then 'Follow-Up #1' when status='completed' then 'Future Opportunity' else 'New Lead' end,coalesce(contact_name,owner_contact_name),coalesce(business_name,campaign_name),email,phone,city,county,state,category,campaign_type,coalesce(assigned_sender,'unassigned'),case when campaign_type='political' or category='Political Outreach' then 120000 when campaign_type='supplyfy' or category='Procurement / Supplify' then 45000 else 30000 end,case when email is not null then 35 else 20 end,case when priority in ('high','urgent') then 70 else 45 end,case when follow_up_date is not null and follow_up_date<=current_date then 80 else 35 end,case when priority='urgent' then 75 when priority='high' then 62 else 40 end,case when priority='urgent' then 90 when priority='high' then 75 else 45 end,last_contacted_at,case when status='queued' then 'Review queued outreach and approve the next contact.' when status='follow_up' then 'Send or approve the next follow-up.' when status='do_not_contact' or opted_out_at is not null then 'Keep suppressed. Do not contact.' else 'Assign owner and choose the next approved outreach step.' end,follow_up_date::timestamptz,case when email is not null then 'email' when phone is not null then 'call' when facebook_url is not null or messenger_url is not null then 'facebook_dm' else 'manual' end,case when status='do_not_contact' or opted_out_at is not null then 'suppressed' when status='completed' then 'completed' else 'active' end,website,coalesce(metadata,'{}'::jsonb)||jsonb_build_object('source_table',source_table,'source_id',source_id,'lead_source',source,'priority',priority),created_at,updated_at from public.outreach_prospects on conflict (source_system, source_id) do update set business_line=excluded.business_line, primary_stage=excluded.primary_stage, lead_name=excluded.lead_name, organization_name=excluded.organization_name, contact_email=excluded.contact_email, contact_phone=excluded.contact_phone, city=excluded.city, county=excluded.county, state=excluded.state, category=excluded.category, campaign_type=excluded.campaign_type, assigned_owner_key=excluded.assigned_owner_key, estimated_value_cents=excluded.estimated_value_cents, engagement_score=excluded.engagement_score, response_likelihood_score=excluded.response_likelihood_score, urgency_score=excluded.urgency_score, conversion_probability_score=excluded.conversion_probability_score, revenue_priority_score=excluded.revenue_priority_score, latest_outreach_at=excluded.latest_outreach_at, next_action=excluded.next_action, next_action_due_at=excluded.next_action_due_at, next_recommended_channel=excluded.next_recommended_channel, status=excluded.status, source_url=excluded.source_url, metadata=public.revenue_pipeline_items.metadata||excluded.metadata, updated_at=now();
insert into public.revenue_pipeline_tasks (pipeline_item_id,source_system,source_id,task_type,channel,title,detail,assigned_owner_key,due_at,priority,approval_required,dedupe_key,metadata) select item.id,item.source_system,item.source_id,case when item.primary_stage='Replied' then 'reply' when item.primary_stage like 'Follow-Up%' then 'send_follow_up' when item.primary_stage='Intake Started' then 'recover_intake' when item.primary_stage='Proposal Sent' then 'send_follow_up' when item.assigned_owner_key is null or item.assigned_owner_key='unassigned' then 'assign_owner' else 'next_action' end,coalesce(item.next_recommended_channel,'manual'),case when item.primary_stage='Replied' then 'Reply waiting' when item.primary_stage like 'Follow-Up%' then 'Follow-up due' when item.primary_stage='Intake Started' then 'Recover abandoned intake' when item.primary_stage='Proposal Sent' then 'Proposal follow-up' when item.assigned_owner_key is null or item.assigned_owner_key='unassigned' then 'Assign owner' else 'Next revenue action' end,coalesce(item.next_action,'Review this opportunity and choose the next approved step.'),coalesce(item.assigned_owner_key,'unassigned'),coalesce(item.next_action_due_at,now()),case when item.urgency_score>=80 or item.revenue_priority_score>=85 then 'urgent' when item.urgency_score>=55 or item.revenue_priority_score>=65 then 'high' when item.urgency_score>=30 then 'medium' else 'low' end,true,concat('pipeline:',item.source_system,':',item.source_id,':',item.primary_stage),jsonb_build_object('primary_stage',item.primary_stage,'business_line',item.business_line,'revenue_priority_score',item.revenue_priority_score) from public.revenue_pipeline_items item where item.status='active' and item.primary_stage not in ('Closed Won','Closed Lost','Do Not Contact','Future Opportunity') on conflict do nothing;
insert into public.revenue_strategy_insights (insight_type,title,detail,recommendation,evidence,confidence,impact,expires_at) values ('focus','Work replied and interested leads before scaling new volume','Revenue speed is usually won in response handling and follow-up consistency before more top-of-funnel sends.','Start each day with replies, overdue follow-ups, abandoned intake, and proposal-stage opportunities before approving new outreach.','{"source":"default_revenue_os_guardrail"}'::jsonb,0.8800,'high',now()+interval '14 days'),('risk','Protect sender reputation before adding volume','Small sender caps, reply tracking, bounce monitoring, and suppression checks remain more important than raw send count.','Keep automation approval-gated while sender health is still warming up. Increase only after reply quality and bounce risk are visible.','{"source":"deliverability_reputation_control_layer"}'::jsonb,0.9200,'high',now()+interval '14 days') on conflict do nothing;
alter table public.revenue_pipeline_items enable row level security; alter table public.revenue_pipeline_tasks enable row level security; alter table public.revenue_strategy_insights enable row level security;
drop policy if exists revenue_pipeline_items_service on public.revenue_pipeline_items; create policy revenue_pipeline_items_service on public.revenue_pipeline_items for all to service_role using (true) with check (true);
drop policy if exists revenue_pipeline_items_admin_sales_read on public.revenue_pipeline_items; create policy revenue_pipeline_items_admin_sales_read on public.revenue_pipeline_items for select to authenticated using ((auth.jwt()->'app_metadata'->>'user_role') in ('admin','sales_agent'));
drop policy if exists revenue_pipeline_tasks_service on public.revenue_pipeline_tasks; create policy revenue_pipeline_tasks_service on public.revenue_pipeline_tasks for all to service_role using (true) with check (true);
drop policy if exists revenue_pipeline_tasks_admin_sales_read on public.revenue_pipeline_tasks; create policy revenue_pipeline_tasks_admin_sales_read on public.revenue_pipeline_tasks for select to authenticated using ((auth.jwt()->'app_metadata'->>'user_role') in ('admin','sales_agent'));
drop policy if exists revenue_strategy_insights_service on public.revenue_strategy_insights; create policy revenue_strategy_insights_service on public.revenue_strategy_insights for all to service_role using (true) with check (true);
drop policy if exists revenue_strategy_insights_admin_sales_read on public.revenue_strategy_insights; create policy revenue_strategy_insights_admin_sales_read on public.revenue_strategy_insights for select to authenticated using ((auth.jwt()->'app_metadata'->>'user_role') in ('admin','sales_agent'));
comment on column public.sales_leads.revenue_stage is 'Executive primary pipeline stage. A lead should occupy one primary stage at a time.'; comment on table public.revenue_pipeline_items is 'Unified additive revenue pipeline layer spanning sales leads, outreach prospects, intake, approvals, and future channels.'; comment on table public.revenue_pipeline_tasks is 'Automatic accountability queue for next actions, reminders, approvals, follow-ups, and recovery tasks.'; comment on table public.revenue_strategy_insights is 'AI/strategy recommendations for focus, timing, messaging, sender health, and conversion optimization.';;
